+++ 
@@ -0,0 +1,315 @@
+// ===== 全局重置 & CSS 变量 =====
+* {
+  margin: 0;
+  padding: 0;
+  box-sizing: border-box;
+}
+
+:root {
+  --primary: #4f6ef7;
+  --primary-hover: #3b5de7;
+  --bg: #f7f8fa;
+  --card-bg: #ffffff;
+  --text: #1d2129;
+  --text-secondary: #86909c;
+  --border: #e5e6eb;
+  --radius: 12px;
+  --shadow: 0 1px 4px rgba(0, 0, 0, 0.06);
+  --code-bg: #f0f2f5;
+  --code-color: #d63384;
+  --pre-bg: #1e1e2e;
+  --pre-color: #cdd6f4;
+  --hover-bg: #eef1f5;
+  --active-bg: #f0f5ff;
+  --drop-bg: #fafbfc;
+  --status-warn-bg: #fff7e6;
+  --status-warn-text: #d46b08;
+  --status-ok-bg: #f6ffed;
+  --status-ok-text: #389e0d;
+  --status-err-bg: #fff1f0;
+  --status-err-text: #cf1322;
+  --danger-hover-bg: #fff1f0;
+  --user-bubble: #242424;
+  --user-bubble-text: #ffffff;
+}
+
+// 暗色主题
+[data-theme="dark"] {
+  --primary: #6b8aff;
+  --primary-hover: #5a7af5;
+  --bg: #4b4b4b;
+  --card-bg: #1e1e22;
+  --text: #e8e8eb;
+  --text-secondary: #8b8d98;
+  --border: #2e2e35;
+  --shadow: 0 1px 4px rgba(0, 0, 0, 0.3);
+  --code-bg: #2a2a32;
+  --code-color: #f0a0c0;
+  --pre-bg: #111114;
+  --pre-color: #cdd6f4;
+  --hover-bg: #2c2c33;
+  --active-bg: #252a3a;
+  --drop-bg: #222228;
+  --status-warn-bg: #2a2210;
+  --status-warn-text: #faad14;
+  --status-ok-bg: #1a2a18;
+  --status-ok-text: #52c41a;
+  --status-err-bg: #2a1818;
+  --status-err-text: #ff6b6b;
+  --danger-hover-bg: #2a1818;
+  --user-bubble: #ffffff;
+  --user-bubble-text: #1a1a1a;
+}
+
+body {
+  font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Hiragino Sans GB',
+    'Microsoft YaHei', 'Helvetica Neue', Arial, sans-serif;
+  background: var(--bg);
+  color: var(--text);
+  line-height: 1.6;
+  min-height: 100vh;
+  margin: 0;
+}
+
+#app {
+  max-width: 100%;
+  margin: 0;
+  padding: 0;
+  text-align: left;
+}
+
+// ===== 布局 =====
+.app-container {
+  display: flex;
+  height: 100vh;
+  overflow: hidden;
+}
+
+.middle-container {
+  flex: 1;
+  display: flex;
+  flex-direction: column;
+  height: 100vh;
+  overflow: hidden;
+  position: relative;
+  min-width: 0; // 防止 flex 子项溢出
+}
+
+// ===== 共用按钮 =====
+.btn {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  padding: 8px 20px;
+  background: var(--primary);
+  color: #fff;
+  border: none;
+  border-radius: 8px;
+  font-size: 14px;
+  font-weight: 500;
+  cursor: pointer;
+  transition: background 0.2s;
+  width: 100%;
+
+  &:hover { background: var(--primary-hover); }
+  &:disabled { background: #c9cdd4; cursor: not-allowed; }
+}
+
+// ===== 共用弹窗 =====
+.modal-overlay {
+  position: fixed;
+  inset: 0;
+  background: rgba(0, 0, 0, 0.4);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  z-index: 1000;
+  animation: fadeIn 0.2s;
+}
+
+.modal {
+  background: var(--card-bg);
+  border-radius: 12px;
+  width: 560px;
+  max-width: 90vw;
+  max-height: 70vh;
+  display: flex;
+  flex-direction: column;
+  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.15);
+  animation: slideUp 0.25s;
+  -webkit-border-radius: 12px;
+  -moz-border-radius: 12px;
+  -ms-border-radius: 12px;
+  -o-border-radius: 12px;
+}
+
+.modal-header {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  padding: 20px 16px;
+  border-bottom: 1px solid var(--border);
+
+  h3 { font-size: 16px; font-weight: 600; margin: 0; }
+}
+
+.modal-close {
+  width: 32px;
+  height: 32px;
+  border-radius: 8px;
+  border: none;
+  background: var(--bg);
+  color: var(--text-secondary);
+  font-size: 18px;
+  cursor: pointer;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  transition: all 0.2s;
+
+  &:hover { background: var(--danger-hover-bg); color: #f53f3f; }
+}
+
+.modal-body {
+  flex: 1;
+  overflow-y: auto;
+  padding: 16px 24px;
+}
+
+.modal-empty {
+  text-align: center;
+  color: var(--text-secondary);
+  font-size: 14px;
+  padding: 40px 0;
+}
+
+.modal-footer {
+  padding: 14px 24px;
+  border-top: 1px solid var(--border);
+  display: flex;
+  justify-content: flex-end;
+}
+
+// ===== 共用文本块 =====
+.chunk-item {
+  padding: 8px 12px;
+  background: var(--bg);
+  border-radius: 6px;
+  font-size: 13px;
+  color: var(--text);
+  line-height: 1.5;
+  border-left: 3px solid var(--primary);
+}
+
+.chunk-index {
+  color: var(--primary);
+  font-weight: 600;
+  margin-right: 4px;
+}
+
+// ===== Markdown 渲染 =====
+.markdown-body {
+  white-space: normal;
+  font-size: 14px;
+  line-height: 1.7;
+
+  p { margin: 0 0 10px; &:last-child { margin-bottom: 0; } }
+
+  h1, h2, h3, h4, h5, h6 { margin: 16px 0 8px; font-weight: 600; line-height: 1.4; }
+  h1 { font-size: 1.4em; }
+  h2 { font-size: 1.25em; }
+  h3 { font-size: 1.1em; }
+
+  ul, ol { padding-left: 20px; margin: 8px 0; }
+  li { margin: 4px 0; }
+
+  code {
+    background: var(--code-bg);
+    padding: 2px 6px;
+    border-radius: 4px;
+    font-size: 13px;
+    font-family: 'Menlo', 'Monaco', 'Consolas', 'Courier New', monospace;
+    color: var(--code-color);
+  }
+
+  pre {
+    background: var(--pre-bg);
+    border-radius: 8px;
+    padding: 16px;
+    overflow-x: auto;
+    margin: 10px 0;
+
+    code { background: none; padding: 0; color: var(--pre-color); font-size: 13px; line-height: 1.5; }
+  }
+
+  blockquote {
+    border-left: 3px solid var(--primary);
+    padding: 4px 12px;
+    margin: 8px 0;
+    color: var(--text-secondary);
+    background: var(--bg);
+    border-radius: 0 6px 6px 0;
+  }
+
+  table { border-collapse: collapse; width: 100%; margin: 10px 0; font-size: 13px; }
+  th, td { border: 1px solid var(--border); padding: 8px 12px; text-align: left; }
+  th { background: var(--bg); font-weight: 600; }
+
+  a { color: var(--primary); text-decoration: none; &:hover { text-decoration: underline; } }
+  hr { border: none; border-top: 1px solid var(--border); margin: 12px 0; }
+  strong { font-weight: 600; }
+}
+
+// ===== 全局滚动条 =====
+* {
+  scrollbar-width: thin;
+  scrollbar-color: rgba(0, 0, 0, 0.15) transparent;
+}
+
+::-webkit-scrollbar {
+  width: 6px;
+  height: 6px;
+}
+
+::-webkit-scrollbar-track {
+  background: transparent;
+}
+
+::-webkit-scrollbar-thumb {
+  background: rgba(0, 0, 0, 0.12);
+  border-radius: 3px;
+
+  &:hover {
+    background: rgba(0, 0, 0, 0.2);
+  }
+}
+
+[data-theme="dark"] {
+  scrollbar-color: rgba(255, 255, 255, 0.12) transparent;
+
+  ::-webkit-scrollbar-thumb {
+    background: rgba(255, 255, 255, 0.1);
+
+    &:hover {
+      background: rgba(255, 255, 255, 0.18);
+    }
+  }
+}
+
+// ===== 动画 =====
+@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
+@keyframes slideUp { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
+
+// ===== 图标工具类 =====
+button, .btn, .history-btn, .new-chat-btn, .welcome-hint,
+.session-menu-item, .preview-tab, .preview-meta, .ref-toggle {
+  display: flex;
+  align-items: center;
+  gap: 6px;
+}
+
+h3 {
+  display: flex;
+  align-items: center;
+  gap: 6px;
+}

